_step_1_create_header_component.css:
:host { display: block; position: sticky; top: 0; z-index: 20; background-color: #ffffff; }
.hdr { display: flex; justify-content: space-between; align-items: center; padding: 1rem 2rem; }
.logo { font-weight: 700; text-decoration: none; color: var(--heading); }
nav { display: flex; gap: 1.5rem; }
nav a { color: var(--body-text); text-decoration: none; }
nav a:hover { color: var(--primary); }
